import React from 'react';
import AcompanhamentoTVpA from '../components/AcompanhamentoTVpA';
import { useLocation } from 'react-router-dom';

const NovoRelatorioTVpA = () => {
	const location = useLocation();
	const params = new URLSearchParams(location.search);
	const razaoSocial = params.get('razaoSocial') || '';
	return <AcompanhamentoTVpA razaoSocial={razaoSocial} />;
};

export default NovoRelatorioTVpA;
